-- Run this in Supabase Dashboard → SQL Editor
-- Adds tags column if missing, then upserts all 25 founders

alter table founders add column if not exists tags text[] default '{}';

on conflict (slug) do update
  set name     = excluded.name,
      initials = excluded.initials,
      title    = excluded.title,
      company  = excluded.company,
      quote    = excluded.quote,
      tags     = excluded.tags;

-- Verify
select count(*) as total_founders from founders;
